export function getBlogLocale(blog, lang) {
  const exact = blog.locales.find((l) => l.language === lang);
  return exact || blog.locales.find((l) => l.language === 'en') || blog.locales[0];
}

export function getBlogSlug(blog, lang) {
  const locale = getBlogLocale(blog, lang);
  const localeSlug = (locale?.slug || '').trim();
  return localeSlug || blog.slug;
}

export function getBlogSlugByBaseSlug(baseSlug, lang) {
  if (!baseSlug) return '';
  const blog = blogContent.find((item) => item.slug === baseSlug);
  return blog ? getBlogSlug(blog, lang) : baseSlug;
}

export function matchesBlogSlug(blog, slug) {
  if (!slug) return false;
  if (blog.slug === slug) return true;
  return (blog.locales || []).some((locale) => locale.slug === slug);
}